from typing import Generator, TypeVar, Callable, Iterable
T = TypeVar('T')
R = TypeVar('R')

def batch_process(items: Iterable[T], batch_size: int, processor: Callable[[list[T]], list[R]]) -> Generator[R, None, None]:
    batch = []
    for item in items:
        batch.append(item)
        if len(batch) == batch_size:
            yield from processor(batch)
            batch = []
    if batch:
        yield from processor(batch)

